const dataManager = new ClientDataManager();

function App() {
  return (
    <DataSourceProvider dataManager={dataManager}>
      <MyApp />
    </DataSourceProvider>
  );
}

const dataSource = makePlainQueryDataSource({
  name: 'status',
  fetch: skipContext(fetchStatus),
  options: {
    refetchInterval: getProgressiveRefetch({ minInterval: 1000, maxInterval: 30000 }),
  },
});

const postsDataSource = makeInfiniteQueryDataSource({
  name: 'posts',
  fetch: skipContext(fetchPosts),
  next: (lastPage) => lastPage.hasMore ? { cursor: lastPage.nextCursor } : undefined,
});

const userDataSource = makePlainQueryDataSource({
  name: 'user',
  fetch: skipContext(fetchUser),
  tags: (params) => [`user:${params.userId}`, 'users'],
});

const dataSource = makePlainQueryDataSource({
  name: 'user',
  fetch: skipContext(fetchUser), // fetchUser(params) becomes compatible
});
